func Test_AnthropicToolCalling(t *testing.T) {
	// Chat request to Anthropic provider with a tool definition; assistant responds with a tool call
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/anthropic_tool_calling"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Chat(nil)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	assert.Equal(t, len(result.Choices), 1, "expected exactly 1 elements")
	if len(result.Choices["0"].Message.ToolCalls) == 0 {
		t.Errorf("expected non-empty value")
	}
	if strings.TrimSpace(result.Choices["0"].Message.ToolCalls["0"].Function.Name) != `get_weather` {
		t.Errorf("equals mismatch: got %v", result.Choices["0"].Message.ToolCalls["0"].Function.Name)
	}
	if strings.TrimSpace(result.Choices["0"].FinishReason) != `tool_calls` {
		t.Errorf("equals mismatch: got %v", result.Choices["0"].FinishReason)
	}
}

